-- Proporcionar acceso a un nuevo usuario y proporcionarle 
-- su propio certificado 

-- Orden de comandos 
-- Clava privada - primer comando ejecutado 
openssl genrsa -out adam.key 2048 
-- Solicitu de firma de certificado - segundo comando ejecutado
openssl req -new -key adam.key -out adam.csr -subj "/CN=adam"

-- Para crear un nuevo usuario en kubernetes, debemos de pasar el 
-- certificado a una base64 para el archivo de configuración yaml 
-- entonces debemos de ejecutar el siguiente comando para configurar 
-- el certificado en base64 y pasarlo en el campo de request del yaml

cat adam.csr | base64 | tr -d "\n"


# Aplicar firma de certificado 
k apply -f csr.yaml

# Ver la firma de certificado creada 
k get csr 

# ver la descripción de una firma de un certificado 
k describe csr adam 

# aprovar la firma de un certificado 
kubectl certificate approve adam

# luego podemos compartir el certificado con el usuario para que pueda acceder al cluster
k get csr adam -o yaml > issuecert.yaml

# luego decodificamos el certificado para que el usuario pueda usarlo 
echo "" | base64 -d